/**
 * Insert stage_category_eval records for all candidate scores
 *
 * @param client - PostgreSQL client (within transaction)
 * @param stageId - Stage ID from classification_stage
 * @param candidateScores - Map of category scores
 */
async function insertStageCategoryEvals(
  client: PoolClient,
  stageId: number,
  candidateScores: Record<
    string,
    {
      score: number;
      confidence?: number;
      decision?: string;
      selectedSubtypeId?: string | null;
      rationale?: string;
      scoringComponents?: Record<string, unknown>;
    }
  >
): Promise<void> {
  for (const [category, scoreData] of Object.entries(candidateScores)) {
    const evalQuery = `
      INSERT INTO email.stage_category_eval (
        stage_id,
        category_code,
        decision,
        score,
        confidence,
        weight_components,
        scoring_components,
        selected_subtype_code,
        rationale
      )
      VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
    `;

    // Database CHECK constraint requires score JSONB to have 'score' and 'confidence' keys
    const scoreJson = {
      score: scoreData.score,
      confidence: scoreData.confidence || 0,
      decision: scoreData.decision || 'candidate',
      rationale: scoreData.rationale || `Category ${category} scored ${scoreData.score}`,
    };

    const evalParams = [
      stageId,
      category,
      scoreData.decision || 'candidate',
      JSON.stringify(scoreJson),
      scoreData.confidence || 0,
      JSON.stringify(scoreData.scoringComponents || {}),
      JSON.stringify(scoreData.scoringComponents || {}),
